import random
import math
import time
from collections import defaultdict
from typing import List, Tuple

def get_best_schedule(workload, num_seqs: int) -> Tuple[int, List[int]]:
    n = workload.num_txns

    if n <= 8:
        best_cost = float('inf')
        best_seq = None
        from itertools import permutations
        for perm in permutations(range(n)):
            cost = workload.get_opt_seq_cost(list(perm))
            if cost < best_cost:
                best_cost = cost
                best_seq = list(perm)
        return best_cost, best_seq

    def get_cost(seq):
        return workload.get_opt_seq_cost(seq)

    read_sets = [set() for _ in range(n)]
    write_sets = [set() for _ in range(n)]
    for i in range(n):
        for op_type, key, _, _ in workload.txns[i]:
            if op_type == 'r':
                read_sets[i].add(key)
            else:
                write_sets[i].add(key)

    conflict_counts = [[0] * n for _ in range(n)]
    for i in range(n):
        for j in range(i + 1, n):
            ww_conflict = len(write_sets[i] & write_sets[j])
            rw_conflict = len(read_sets[i] & write_sets[j])
            wr_conflict = len(write_sets[i] & read_sets[j])
            conflict_counts[i][j] = ww_conflict + rw_conflict + wr_conflict
            conflict_counts[j][i] = conflict_counts[i][j]

    def greedy_conflict_avoid():
        remaining = set(range(n))
        seq = []
        last_added = None

        while remaining:
            if last_added is None:
                candidate = random.choice(list(remaining))
            else:
                candidate = min(remaining, key=lambda x: conflict_counts[last_added][x])
            seq.append(candidate)
            remaining.remove(candidate)
            last_added = candidate
        return seq

    def greedy_insertion():
        if n <= 1:
            return list(range(n))
        order = list(range(n))
        random.shuffle(order)
        seq = [order[0]]
        for txn in order[1:]:
            best_pos = 0
            best_cost = float('inf')
            for pos in range(len(seq) + 1):
                test_seq = seq[:pos] + [txn] + seq[pos:]
                cost = get_cost(test_seq)
                if cost < best_cost:
                    best_cost = cost
                    best_pos = pos
            seq.insert(best_pos, txn)
        return seq

    def beam_search(beam_width=5):
        beam = [([], set(range(n)))]
        for _ in range(n):
            new_beam = []
            for seq, remaining in beam:
                if not remaining:
                    new_beam.append((seq, remaining))
                    continue
                for txn in list(remaining)[:beam_width*2]:
                    new_seq = seq + [txn]
                    new_remaining = remaining - {txn}
                    cost = get_cost(new_seq)
                    new_beam.append((new_seq, new_remaining, cost))
            new_beam.sort(key=lambda x: x[2])
            beam = [(seq, rem) for seq, rem, _ in new_beam[:beam_width]]
        return beam[0][0]

    def mutate(seq):
        seq = seq[:]
        if random.random() < 0.7:
            i, j = random.sample(range(n), 2)
            seq[i], seq[j] = seq[j], seq[i]
        else:
            i, j = sorted(random.sample(range(n), 2))
            seq[i:j+1] = reversed(seq[i:j+1])
        return seq

    def simulated_annealing(initial_seq, iterations=2000):
        current = initial_seq[:]
        current_cost = get_cost(current)
        best = current[:]
        best_cost = current_cost

        for k in range(iterations):
            T = 10.0 * (0.995 ** k)
            neighbor = mutate(current)
            neighbor_cost = get_cost(neighbor)

            delta = neighbor_cost - current_cost
            if delta < 0 or random.random() < math.exp(-delta / max(T, 1e-6)):
                current = neighbor
                current_cost = neighbor_cost
                if neighbor_cost < best_cost:
                    best = neighbor[:]
                    best_cost = neighbor_cost
        return best, best_cost

    def local_search(seq, time_limit=0.05):
        best = seq[:]
        best_cost = get_cost(seq)
        start = time.time()

        while time.time() - start < time_limit:
            i, j = random.sample(range(n), 2)
            neighbor = best[:]
            neighbor[i], neighbor[j] = neighbor[j], neighbor[i]
            neighbor_cost = get_cost(neighbor)
            if neighbor_cost < best_cost:
                best = neighbor[:]
                best_cost = neighbor_cost

        improved = True
        while improved:
            improved = False
            for i in range(n):
                for j in range(i + 1, n):
                    neighbor = best[:]
                    neighbor[i], neighbor[j] = neighbor[j], neighbor[i]
                    neighbor_cost = get_cost(neighbor)
                    if neighbor_cost < best_cost:
                        best = neighbor[:]
                        best_cost = neighbor_cost
                        improved = True
                        break
                if improved:
                    break
        return best, best_cost

    constructors = [greedy_conflict_avoid, greedy_insertion, beam_search]
    best_cost = float('inf')
    best_seq = None

    for _ in range(min(num_seqs, 15)):
        constructor = random.choice(constructors)
        seq = constructor()
        seq, cost = simulated_annealing(seq, iterations=1000)
        if cost < best_cost:
            best_cost = cost
            best_seq = seq

    if best_seq:
        best_seq, best_cost = local_search(best_seq, time_limit=0.1)

    return best_cost, best_seq
